#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,m;
    cin>>n>>m;
    char a[n+1][m+1];
    for (int i=0;i<n;i++){
        for (int j=0;j<m;j++){
            cin>>a[i][j];
        }
    }
    for (int i=n-1;i>0;i--){
        for (int j=0;j<m;j++){
            if (a[i][j]=='.'){
                for(int k=i-1;k>=0;k--){
                    if (a[k][j]=='-') {
                        break;   
                    }
                    else if (a[k][j]!='.') {
                        a[i][j]=a[k][j];
                        a[k][j]='.';
                        break;
                    }    
                }
            }
        }
    }
    for (int i=0;i<n;i++){
        for (int j=0;j<m;j++){
            cout<<a[i][j];
        }
        cout<<endl;
    }
    return 0;
}
